33	/* ---------- Overflow Flow ---------- */
34	
35	const LINE_HEIGHT = 28; // matches leading-7 (1.75rem = 28px)
36	const MAX_LINES = 2;
37	const MAX_HEIGHT = LINE_HEIGHT * MAX_LINES;
38	
39	function FlowSection({
40	  label,
41	  moreHref,
42	  moreLabel,
43	  children,
44	}: {
45	  label: string;
46	  moreHref: string;
47	  moreLabel: string;
48	  children: React.ReactNode;
49	}) {
50	  const measureRef = useRef<HTMLDivElement>(null);
51	  const moreRef = useRef<HTMLSpanElement>(null);
52	  const [visibleCount, setVisibleCount] = useState<number | null>(null);
53	
54	  const items = React.Children.toArray(children);
55	
56	  const measure = useCallback(() => {
57	    const el = measureRef.current;
58	    if (!el) return;
59	    const nodes = el.children;
60	    const itemNodeCount = nodes.length - 2; // exclude label (first) and hidden "more…" span (last)
61	    // Check if everything fits without overflow
62	    if (el.scrollHeight <= MAX_HEIGHT + 4) {
63	      setVisibleCount(items.length);
64	      return;
65	    }
66	    // Measure actual "more…" link width
67	    const moreWidth = moreRef.current ? moreRef.current.offsetWidth + 8 : 52;
68	    const containerWidth = el.offsetWidth;
69	    // First pass: find all items that fit within MAX_HEIGHT (2 lines)
70	    let lastFitting = 0;
71	    for (let i = 1; i <= itemNodeCount; i++) {
72	      const node = nodes[i] as HTMLElement;
73	      if (node.offsetTop + node.offsetHeight > MAX_HEIGHT) break;
74	      lastFitting = i;
75	    }
76	    // Second pass: walk backward from lastFitting until "more…" fits after the item
77	    let count = lastFitting;
78	    while (count > 1) {
79	      const node = nodes[count] as HTMLElement;
80	      const nodeBottom = node.offsetTop + node.offsetHeight;
81	      // If this item is on line 1, "more…" can always wrap to line 2 — we're fine
82	      if (nodeBottom <= LINE_HEIGHT) break;
83	      // Item is on line 2 — check if "more…" fits after it on the same line
84	      const nodeRight = node.offsetLeft + node.offsetWidth;
85	      if (nodeRight + moreWidth <= containerWidth) break;
86	      count--;
87	    }
88	    setVisibleCount(Math.max(1, count));
89	  }, [items.length]);
90	
91	  useEffect(() => {
92	    const raf = requestAnimationFrame(measure);
93	    const obs = new ResizeObserver(measure);
94	    if (measureRef.current) obs.observe(measureRef.current);
95	    return () => {
96	      cancelAnimationFrame(raf);
97	      obs.disconnect();
98	    };
99	  }, [measure, items.length]);
100	
101	  const hasOverflow = visibleCount !== null && visibleCount < items.length;
102	  const displayed = visibleCount !== null ? items.slice(0, visibleCount) : items;
103	
104	  return (
105	    <div className="relative">
106	      {/* Hidden measurer — renders all items to find cutoff */}
107	      <div
108	        ref={measureRef}
109	        className="text-[13px] leading-7"
110	        style={{ position: "absolute", visibility: "hidden", top: 0, left: 0, right: 0, pointerEvents: "none" }}
111	        aria-hidden="true"
112	      >
113	        <span className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5">
114	          {label}:
115	        </span>
116	        {items}
117	        {/* Hidden "more…" to measure its actual width */}
118	        <span ref={moreRef} className="inline-flex items-baseline text-[12px] font-medium whitespace-nowrap">
119	          {moreLabel}
120	        </span>
121	      </div>
122	      {/* Visible section */}
123	      <div className="text-[13px] leading-7">
124	        <span
125	          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5 text-text-muted"
126	          style={{ fontFamily: "var(--font-dm-sans)" }}
127	        >
128	          {label}:
129	        </span>
130	        {displayed}
131	        {hasOverflow && (
132	          <Link
133	            href={moreHref}
134	            className="inline-flex items-baseline text-[12px] font-medium hover:underline whitespace-nowrap text-beacon-accent"
135	          >
136	            {moreLabel}
137	          </Link>
138	        )}
139	      </div>
140	    </div>
141	  );
142	}
